function searchFilter(e,r){for(var t=document.getElementById(e),l=document.getElementById(r),c=new RegExp(t.value,"i"),n=!1,s=1;s<l.rows.length;s++){n=!1;for(var o=l.rows[s].cells.length-1;o>=0&&!(n=c.test(l.rows[s].cells[o].innerHTML));o--);l.rows[s].style.display=n?"":"none"}}document.querySelectorAll(".close-filter").forEach(e=>{e.addEventListener("click",e=>{e.preventDefault(),document.querySelector(".search__filter-properties").classList.toggle("active")})}),document.querySelector("#searchOrder").addEventListener("keyup",()=>{searchFilter("searchOrder","tableOrder")});